UPDATE product SET name_en = 'Egemen Epidural Kit', description_en = '<p>The Egemen Epidural Kit (SKU: TMT-EPIS18903) is designed to meet the rigorous demands of epidural block procedures in a highly controlled surgical setting. This product embodies a fusion of precision and ergonomics, offering impeccable assurance thanks to its medical-grade polycarbonate material, renowned for its biocompatibility and exceptional durability. With a thoughtful design, the device allows for easy handling while minimizing tissue trauma risks with its atraumatic, subtly beveled and graduated tip for precise placement.</p><p>The sterilization of this kit is assured through a rigorous ethylene oxide (EO) process, ensuring optimal performance without compromising material integrity. Each kit is individually packaged in a blister pack, ensuring not only sterility until use but also easy logistical management and seamless integration into clinical protocols.</p><p>CE 0120 certified, the Egemen Epidural Kit complies with European safety and quality standards, providing practitioners with great peace of mind during clinical use. Its length of 85 cm and diameter of 1.2 mm are optimized for smooth introduction, thus facilitating equipment positioning during critical procedures.</p><table class="min-w-full table-auto border-collapse border border-gray-200"><thead><tr class="bg-gray-100"><th class="px-4 py-2 border border-gray-200">Product</th><th class="px-4 py-2 border border-gray-200">Specifications</th></tr></thead><tbody><tr><td class="px-4 py-2 border border-gray-200">Material</td><td class="px-4 py-2 border border-gray-200">Medical-grade Polycarbonate</td></tr><tr class="bg-gray-50"><td class="px-4 py-2 border border-gray-200">Sterilization</td><td class="px-4 py-2 border border-gray-200">Ethylene Oxide (EO)</td></tr><tr><td class="px-4 py-2 border border-gray-200">CE / ISO Compliance</td><td class="px-4 py-2 border border-gray-200">CE 0120</td></tr><tr class="bg-gray-50"><td class="px-4 py-2 border border-gray-200">Clinical Use</td><td class="px-4 py-2 border border-gray-200">Epidural block for surgical intervention</td></tr><tr><td class="px-4 py-2 border border-gray-200">Features</td><td class="px-4 py-2 border border-gray-200">Atraumatic tip with graduated bevel, Individual blister packaging</td></tr></tbody></table>' WHERE id = 63;
UPDATE product SET name_en = 'Catheter Tip Syringe - Latex-Free 3-Part Syringe - 50ml', description_en = '<p class="text-lg text-gray-800 mt-4">The <strong>Catheter Tip Syringe - Latex-Free 3-Part Syringe - 50 ml</strong> is designed to meet the most demanding needs of healthcare professionals for fluid administration. Made of latex-free polypropylene, this syringe ensures superior biocompatibility and minimizes hypersensitivity risks in patients. The three-part design offers increased ergonomics and maneuverability, allowing for optimal precision during administration.</p><p class="text-lg text-gray-800 mt-4">Equipped with a catheter tip, the syringe enables atraumatic and precise insertion. This type of tip is particularly suitable for procedures requiring impeccable precision and total fluid control. Each of these syringes is sterilized with ethylene oxide (EO), ensuring reliable sterility in compliance with the most stringent clinical standards.</p><p class="text-lg text-gray-800 mt-4">Each syringe is packaged in a sterile individual packaging, ensuring maximum protection against contaminants until use. The syringe receives CE certification, illustrating its adherence to European safety and performance standards in medical devices. Designed for single use, it is ideal for clinical applications requiring precise and secure administration.</p><p class="text-lg text-gray-800 mt-4">With a capacity of 50 ml, it is perfectly suited to a variety of medical-clinical applications, offering both reliability and efficiency for critical and regular care. Its latex-free construction eliminates the risk of latex allergic reactions while ensuring high-level integrity and performance.</p><table class="min-w-full bg-white"><thead><tr><th class="px-4 py-2 border-b-2 border-gray-200 bg-gray-100 text-left text-xs font-semibold text-gray-600 uppercase">Specification</th><th class="px-4 py-2 border-b-2 border-gray-200 bg-gray-100 text-left text-xs font-semibold text-gray-600 uppercase">Detail</th></tr></thead><tbody><tr class="bg-gray-50"><td class="px-4 py-2 border-b border-gray-200">Material</td><td class="px-4 py-2 border-b border-gray-200">Latex-free Polypropylene</td></tr><tr><td class="px-4 py-2 border-b border-gray-200">Sterilization</td><td class="px-4 py-2 border-b border-gray-200">Ethylene Oxide (EO)</td></tr><tr class="bg-gray-50"><td class="px-4 py-2 border-b border-gray-200">Compliance</td><td class="px-4 py-2 border-b border-gray-200">CE Certification</td></tr><tr><td class="px-4 py-2 border-b border-gray-200">Clinical Use</td><td class="px-4 py-2 border-b border-gray-200">Single use for precise administration</td></tr><tr class="bg-gray-50"><td class="px-4 py-2 border-b border-gray-200">Features</td><td class="px-4 py-2 border-b border-gray-200">Individual sterile packaging, Catheter tip, Advanced ergonomics</td></tr></tbody></table>' WHERE id = 564;
UPDATE product SET name_en = 'Coloplast Urostomy Bag 2-Piece (Multi-Sizes)', description_en = '<p>The Coloplast Urostomy Bag 2-Piece is a urinary management solution designed for professional clinical use. Made of medical-grade polyurethane, this device offers optimal biocompatibility, minimizing the risk of traumatic reactions and ensuring patient comfort. The polyurethane material is recognized for its durability and resistance, while being lightweight and flexible, crucial for atraumatic care and prolonged integration with the patient''s body.</p><p>CE 2460 certified, this product meets the most stringent European standards in terms of medical safety and performance. Sterilization using Ethylene Oxide (EO) provides effective microbial load reduction, offering an essential aseptic barrier. This process ensures that each unit, individually packaged, remains sterile until use, protecting patients and medical staff from potential contamination.</p><p>The adjustable multi-size design of this urostomy bag allows great flexibility of use, adapting to the specific needs of each patient and clinical situation. Designed to easily integrate into the 2-piece system, this product offers exceptional compatibility, simplifying continuous care processes. Its ergonomic structure ensures effortless application and removal, thereby reducing potential trauma for the patient.</p><table class="table-auto w-full"><thead><tr class="bg-gray-100"><th class="px-4 py-2">Property</th><th class="px-4 py-2">Description</th></tr></thead><tbody><tr><td class="border px-4 py-2">Material</td><td class="border px-4 py-2">Medical-grade Polyurethane</td></tr><tr class="bg-gray-50"><td class="border px-4 py-2">Sterilization</td><td class="border px-4 py-2">Ethylene Oxide (EO)</td></tr><tr><td class="border px-4 py-2">CE / ISO Compliance</td><td class="border px-4 py-2">CE 2460</td></tr><tr class="bg-gray-50"><td class="border px-4 py-2">Clinical Use</td><td class="border px-4 py-2">Professional clinical use</td></tr><tr><td class="border px-4 py-2">Features</td><td class="border px-4 py-2">Adjustable multi-size dimensions, 2-piece system compatibility, Individual sterile packaging</td></tr></tbody></table>' WHERE id = 508;
UPDATE product SET name_en = 'First Aid/Emergency Kit', description_en = '<p>The First Aid/Emergency Kit (SKU: KIT-URG-001) is a meticulously designed set of medical equipment for quick and effective intervention in medical emergencies. This kit is ideal for healthcare professionals, first responders, and medical environments requiring immediate access to reliable and high-quality first aid tools. Each component is selected to ensure optimal performance while guaranteeing maximum safety for both the caregiver and the patient.</p><p>The stainless steel 304 scissors are highly durable and offer high biocompatibility, ensuring atraumatic usage when cutting bandages or clothing. The compresses are sterilized using ethylene oxide (EO), a process known for effectively eliminating pathogens while preserving the integrity of the sterilized material. The survival blanket, measuring 210 x 160 cm, provides essential thermal protection in emergencies, minimizing the risks of hypothermia and shock.</p><p>Every element of this kit, including the hypoallergenic microporous tape, is carefully packaged to maintain sterility and efficacy. The product conforms to CE standards, ensuring compliance with international quality standards. This kit is conveniently compact and ergonomic, facilitating its transport and practical use in any emergency situation.</p><style>.table {width: 100%;border-collapse: collapse;margin-top: 20px;}.table th, .table td {border: 1px solid #ccc;padding: 8px;text-align: left;}.table th {background-color: #f9f9f9;}</style><table class="table"><tr><th>Features</th><th>Details</th></tr><tr><td>Material</td><td>Stainless Steel 304 (scissors), Hypoallergenic microporous (tape)</td></tr><tr><td>Sterilization</td><td>Ethylene Oxide (compresses)</td></tr><tr><td>Compliance</td><td>CE Compliant</td></tr><tr><td>Clinical Use</td><td>First aid equipment for emergency intervention</td></tr><tr><td>Features</td><td>Contains 1 unit per item type, survival blanket dimensions 210 x 160 cm</td></tr></table>' WHERE id = 10005;
UPDATE product SET name_en = 'Reinforced Intubation Tube (Multi-Sizes)', description_en = '<p>The reinforced intubation tube RUS104202-000035 is meticulously designed to seamlessly integrate into high-demand hospital and clinical environments. Made from Stainless Steel 304, renowned for its high resistance to corrosion, it ensures not only a durable user experience but also provides high biocompatibility essential for quality medical care.</p><p>Sterilized using ethylene oxide, the tube offers optimal safety by minimizing nosocomial infection risks. It meets strict CE standards, proving its adherence to international quality and safety norms. Available in multiple sizes ranging from 6 to 12 mm in diameter, it allows precise adaptation to the specific needs of each clinical intervention.</p><p>Its design features a soft, atraumatic tip that prevents trauma during insertion, preserving the integrity of sensitive tissues. Moreover, each tube is packaged in individual sterile packaging, allowing for complete aseptic handling. This attention to detail and user comfort makes this tube an indispensable choice for professionals seeking to combine clinical efficiency with adherence to best care practices.</p><table class="min-w-full border-collapse"><thead><tr><th class="border-b py-2">Specification</th><th class="border-b py-2">Details</th></tr></thead><tbody><tr><td class="border-t py-2">Material</td><td class="border-t py-2">Stainless Steel 304</td></tr><tr><td class="border-t py-2">Sterilization</td><td class="border-t py-2">Ethylene Oxide (EO)</td></tr><tr><td class="border-t py-2">CE / ISO Compliance</td><td class="border-t py-2"><span class="font-bold">CE</span></td></tr><tr><td class="border-t py-2">Clinical Use</td><td class="border-t py-2">Clinical and hospital use</td></tr><tr><td class="border-t py-2">Features</td><td class="border-t py-2">Sizes from 6 to 12 mm (diameter), Soft atraumatic tips</td></tr></tbody></table>' WHERE id = 31;
