UPDATE product SET name_en = 'Left-Sided Selective Intubation Tube Kit Ch41', description_en = '<div style="font-family: Arial, sans-serif; line-height: 1.6;"> <p style="margin-bottom: 16px;"> The Left-Sided Selective Intubation Tube Kit Ch41, referenced under SKU: RUS116100-000410, represents the pinnacle of modern airway management technology. Designed to maximize safety and efficiency in the intubation process, this kit is specifically dedicated to left lung selective intubation, offering unmatched precision in complex surgical procedures. Its medical-grade silicone construction ensures optimal biocompatibility, reducing the risk of adverse reactions. </p> <p style="margin-bottom: 16px;"> The tube has been carefully sterilized by ethylene oxide (EO), guaranteeing impeccable sterility until opened. This meticulous sterilization process complies with the highest standards, ensuring uncompromising safety while meeting CE certifications. This single-use product is packaged in sterile packaging, ready for use to ensure the hygiene and asepsis required in hospital settings. </p> <p style="margin-bottom: 16px;"> Ergonomically, our Ch41 Intubation Tube Kit has been developed to offer atraumatic handling, thanks to a meticulous design based on feedback from healthcare professionals. Its lightweight and flexible design ensures effortless insertion, while the advanced design promotes a precise fit in the airways, thus minimizing potential discomfort for the patient. </p> <table class="min-w-full bg-white" style="border-collapse: collapse;"> <thead> <tr> <th class="px-4 py-2 border" style="text-align: left; background-color: #f9fafb;">Specification</th> <th class="px-4 py-2 border" style="text-align: left; background-color: #f9fafb;">Details</th> </tr> </thead> <tbody> <tr> <td class="px-4 py-2 border">Material</td> <td class="px-4 py-2 border">Medical-grade silicone</td> </tr> <tr> <td class="px-4 py-2 border">Sterilization</td> <td class="px-4 py-2 border">Ethylene oxide (EO)</td> </tr> <tr> <td class="px-4 py-2 border">Compliance</td> <td class="px-4 py-2 border">CE</td> </tr> <tr> <td class="px-4 py-2 border">Clinical Use</td> <td class="px-4 py-2 border">Left-sided selective intubation</td> </tr> <tr> <td class="px-4 py-2 border">Features</td> <td class="px-4 py-2 border">Sterile, single-use</td> </tr> </tbody> </table> </div>' WHERE id = 38;
UPDATE product SET name_en = 'Right-Angled Combined Bacterial Filter Humidifier for Ventilation', description_en = '<p>The Right-Angled Combined Bacterial Filter Humidifier for Ventilation, SKU RUS18402T, is a technological advancement in clinical ventilation. Designed to meet the highest performance standards, this medical device excels in both bacterial filtration and air humidification. Made from medical-grade polypropylene, it ensures optimal biocompatibility, minimizing the risk of irritation or adverse reactions during prolonged use.</p> <p>The product''s ergonomics have been carefully studied to ensure atraumatic fitting to ventilation systems in demanding clinical environments. With a bacterial filtration efficiency of ≥ 99.99%, this filter is vital in clinical scenarios where preventing airborne infections is paramount. Each unit is sterilized through ethylene oxide, ensuring sterility while preserving the integrity of its materials. This device is certified compliant with CE ISO 13485, ensuring its adherence to stringent safety and performance requirements for medical devices.</p> <p>Individually sterile packaging ensures practical and immediate use in clinical settings. With compact dimensions—10 cm in length and a diameter of 2 cm—the filter integrates easily into ventilation systems, optimizing patient comfort and clinical efficiency. This device is an ideal choice for healthcare facilities that value quality, safety, and patient-centered care.</p> <table class="w-full text-left text-sm"> <thead> <tr class="border-b"> <th class="px-4 py-2">Specification</th> <th class="px-4 py-2">Details</th> </tr> </thead> <tbody> <tr class="border-b"> <td class="px-4 py-2">Material</td> <td class="px-4 py-2">Medical-grade polypropylene</td> </tr> <tr class="border-b"> <td class="px-4 py-2">Sterilization</td> <td class="px-4 py-2">Ethylene oxide (EO)</td> </tr> <tr class="border-b"> <td class="px-4 py-2">CE / ISO Compliance</td> <td class="px-4 py-2">CE compliant with ISO 13485 standard</td> </tr> <tr class="border-b"> <td class="px-4 py-2">Clinical Use</td> <td class="px-4 py-2">Filtration and humidification in ventilation systems</td> </tr> <tr> <td class="px-4 py-2">Features</td> <td class="px-4 py-2">Bacterial efficiency ≥ 99.99%</td> </tr> </tbody> </table><p>This medical device is crafted with high-quality clinical materials. Key technical features: <strong>Filter Type</strong>: HMEF (Heat and Moisture Exchange + Bacterial Filter). <strong>Efficiency (BFE/VFE)</strong>: > 99.999%. <strong>Flow Resistance</strong>: 1.5 cmH2O at 30 L/min. <strong>Dead Space</strong>: 45 ml. <strong>Water Output</strong>: 32 mg/H2O at VT 500ml. <strong>Clinical Use</strong>: Anesthesia and ventilation (Protects the patient and ventilator).</p>' WHERE id = 57;
UPDATE product SET name_en = 'Non-Powdered Latex Surgical Gloves (Multi-Sizes)', description_en = '<p>The Non-Powdered Latex Surgical Gloves are designed to meet the stringent demands of high-precision medical environments. Made from premium natural latex, these gloves offer exceptional biocompatibility, minimizing the risk of allergic reactions while ensuring optimal protection for healthcare professionals. Their ambidextrous design allows practical and ergonomic use, fitting each user perfectly while providing remarkable tactile sensation and unparalleled dexterity.</p> <p>Certified with CE, these gloves comply with the most rigorous standards for medical devices, ensuring their reliability and efficacy in critical clinical procedures. Sterilization by ethylene oxide (EO) ensures that the gloves remain perfectly sterile until use, guaranteeing safety for both practitioners and patients. This atraumatic approach reduces the risk of cross-contamination and protects the integrity of sterile surgical environments.</p> <p>Available in multiple sizes, including small, medium, and large, these gloves are designed to suit a wide range of healthcare professionals, from surgical operations to patient examinations. Each box contains 100 units, optimizing storage while ensuring practitioners always have a sufficient supply on hand. This product represents the perfect blend of advanced technology and constant concern for clinical safety and efficacy.</p> <table class="table-auto w-full text-left border border-collapse"> <tr class="border-b"> <th class="p-2 font-bold">Material</th> <td class="p-2">Natural latex</td> </tr> <tr class="border-b"> <th class="p-2 font-bold">Sterilization</th> <td class="p-2">Ethylene oxide (EO)</td> </tr> <tr class="border-b"> <th class="p-2 font-bold">CE / ISO Compliance</th> <td class="p-2">CE certified</td> </tr> <tr class="border-b"> <th class="p-2 font-bold">Clinical Use</th> <td class="p-2">Professional clinical or hospital use</td> </tr> <tr class="border-b"> <th class="p-2 font-bold">Features</th> <td class="p-2">Non-powdered, Ambidextrous, Multi-Sizes</td> </tr> </table>' WHERE id = 536;
UPDATE product SET name_en = 'Disposable Flexible Ureteroscope', description_en = '<p class="font-serif text-gray-800 text-lg">The Disposable Flexible Ureteroscope, model OTU-100RR, is a cutting-edge innovation for healthcare professionals specializing in urological procedures. Manufactured from medical-grade polyurethane, this product boasts superior biocompatibility, ensuring patient safety and comfort during delicate endourological procedures. Designed for single use, it eliminates any risk of cross-contamination, underscoring a commitment to high hygiene standards.</p> <p class="mt-4 font-serif text-gray-800 text-lg">With compact dimensions of 5 Fr diameter and 600 mm length, it allows easy handling and precise penetration, effectively reaching targeted areas within the urinary tract. Featuring a flexible, atraumatic tip, it ensures smooth passage, minimizing patient discomfort and optimizing procedural outcomes. Ergonomically designed for optimal maneuverability, it enables clinicians to navigate with precision and confidence.</p> <p class="mt-4 font-serif text-gray-800 text-lg">This device is sterilized using ethylene oxide (EO), ensuring complete disinfection. Complying with rigorous CE standards, it results from a robust manufacturing process adhering to high quality and reliability levels. This sterile medical instrument is individually packaged, guaranteeing its sterility until time of use. The Disposable Flexible Ureteroscope stands as an essential tool in the arsenal of solutions offered by urological specialists for safe and effective interventions.</p> <table class="mt-6 table-auto w-full border-collapse bg-white shadow overflow-hidden"> <thead> <tr> <th class="px-4 py-2 border-b-2 border-gray-300 bg-gray-100 text-left">Specification</th> <th class="px-4 py-2 border-b-2 border-gray-300 bg-gray-100 text-left">Details</th> </tr> </thead> <tbody> <tr> <td class="border-t border-gray-200 px-4 py-2">Material</td> <td class="border-t border-gray-200 px-4 py-2">Medical-grade polyurethane</td> </tr> <tr> <td class="border-t border-gray-200 px-4 py-2">Sterilization</td> <td class="border-t border-gray-200 px-4 py-2">Ethylene oxide (EO)</td> </tr> <tr> <td class="border-t border-gray-200 px-4 py-2">CE / ISO Compliance</td> <td class="border-t border-gray-200 px-4 py-2">CE</td> </tr> <tr> <td class="border-t border-gray-200 px-4 py-2">Clinical Use</td> <td class="border-t border-gray-200 px-4 py-2">Single use</td> </tr> <tr> <td class="border-t border-gray-200 px-4 py-2">Features</td> <td class="border-t border-gray-200 px-4 py-2">Flexible and atraumatic</td> </tr> </tbody> </table>' WHERE id = 532;
UPDATE product SET name_en = 'Coloplast Easicath Female Catheter (Multi-Sizes)', description_en = '<p>The Coloplast Easicath Female Catheter (Multi-Sizes) is designed to offer an atraumatic, effective, and ergonomic solution for intermittent urinary catheterization in women. Meticulously crafted from medical PVC, free from phthalates, this medical device ensures optimal safety and reduces the risk of tissue irritation.</p> <p>Thanks to its ethylene oxide sterilization process, the catheter ensures a high level of sterility, essential for preventing nosocomial infections. Its rounded, hydrophilic tip design facilitates an atraumatic passage through the urethra, minimizing intervention-related discomfort. This product, designed for single use, ensures patient safety while adhering to the rigorous standards of the CE certification.</p> <p>With sizes ranging from 6 to 12 CH, the Coloplast Easicath Female Catheter is focused on adaptability and patient comfort, making it suitable for both hospital environments and home care. Its individually sterile packaging minimizes the risk of cross-contamination while preserving the product''s integrity until use.</p> <p>Reflecting Coloplast''s commitment to providing innovative healthcare solutions that comply with international clinical and regulatory requirements, this product offers healthcare professionals the confidence necessary for quality care.</p> <table class="min-w-full leading-normal"> <thead> <tr> <th class="px-4 py-2 border-b border-gray-200 bg-gray-100 text-left text-xs font-semibold text-gray-600 uppercase">Specification</th> <th class="px-4 py-2 border-b border-gray-200 bg-gray-100 text-left text-xs font-semibold text-gray-600 uppercase">Details</th> </tr> </thead> <tbody> <tr> <td class="px-4 py-2 border-b border-gray-200 text-sm">Material</td> <td class="px-4 py-2 border-b border-gray-200 text-sm">Phthalate-free medical PVC</td> </tr> <tr> <td class="px-4 py-2 border-b border-gray-200 text-sm">Sterilization</td> <td class="px-4 py-2 border-b border-gray-200 text-sm">Ethylene oxide (EO)</td> </tr> <tr> <td class="px-4 py-2 border-b border-gray-200 text-sm">Compliance</td> <td class="px-4 py-2 border-b border-gray-200 text-sm">CE Certification</td> </tr> <tr> <td class="px-4 py-2 border-b border-gray-200 text-sm">Clinical Use</td> <td class="px-4 py-2 border-b border-gray-200 text-sm">Single use</td> </tr> <tr> <td class="px-4 py-2 border-b border-gray-200 text-sm">Features</td> <td class="px-4 py-2 border-b border-gray-200 text-sm">Rounded hydrophilic tip, individual sterile packaging, sizes 6 to 12 CH</td> </tr> </tbody> </table>' WHERE id = 516;
UPDATE product SET name_en = 'Standard Suture Kit (Complete)', description_en = '<p class="text-lg leading-relaxed mb-4">The Standard Suture Kit (Complete) is designed to meet the requirements of minor clinical interventions, offering high-quality tools to ensure safe and effective outcomes. Made from 304 stainless steel, this kit boasts exceptional biocompatibility and corrosion resistance, ensuring optimal durability even with frequent use. Each instrument is ergonomically designed for prolonged comfort during use, thereby minimizing practitioner fatigue during delicate procedures.</p>

<p class="text-lg leading-relaxed mb-4">Ethylene oxide (EO) sterilization ensures that the kit achieves a high level of sterility, essential for preventing any risk of cross-contamination. The sterile individual packaging preserves the integrity of each instrument until it is used. The kit includes essential tools, such as a 12 cm dissecting forceps, a 14 cm needle holder, and 11 cm IRIS scissors, each designed to perform its function effectively and with atraumatic precision.</p>

<p class="text-lg leading-relaxed mb-4">Compliant with CE and ISO 13485 standards, this kit guarantees unmatched quality and safety, thereby meeting the stringent standards of the modern medical environment. The selection of instruments and manufacturing methodology are optimized to facilitate medical procedures while reducing potential postoperative complications.</p>

