UPDATE product SET name_en = 'Coloplast Female Intermittent Catheter (Multiple Sizes)', description_en = '<p>The Coloplast Female Intermittent Catheter is designed to provide optimal comfort and security during self-catheterization procedures. Made from high-grade medical PVC, this catheter ensures high biocompatibility, thereby minimizing the risk of adverse reactions. Its ethylene oxide sterilization guarantees rigorous asepsis, essential for preventing infection associated with intermittent use.</p><p>Specifically optimized for female use, the catheter is available in multiple sizes, ranging from 10 cm to 20 cm, ensuring adaptability to different individual anatomies. The ergonomic design includes a rounded hydrophilic tip, promoting atraumatic and smooth insertion, reducing discomfort for the user while optimizing urinary drainage efficiency.</p><p>The CE compliance of the Coloplast Female Intermittent Catheter underscores its adherence to the strictest standards of safety and performance. Designed for single use, it is individually packaged, ensuring maximum sterility until opened. This user-centered design emphasizes ease of use and cost-effectiveness, making it ideal for safe and effective clinical use.</p><table class=''min-w-full text-left text-sm''><thead><tr><th class=''px-4 py-2''>Feature</th><th class=''px-4 py-2''>Details</th></tr></thead><tbody><tr><td class=''border px-4 py-2''>Material</td><td class=''border px-4 py-2''>High-grade medical PVC</td></tr><tr><td class=''border px-4 py-2''>Sterilization</td><td class=''border px-4 py-2''>Ethylene Oxide (EO)</td></tr><tr><td class=''border px-4 py-2''>Compliance</td><td class=''border px-4 py-2''>CE Compliant</td></tr><tr><td class=''border px-4 py-2''>Clinical Use</td><td class=''border px-4 py-2''>Sterile single use</td></tr><tr><td class=''border px-4 py-2''>Features</td><td class=''border px-4 py-2''>Available in lengths of 10 cm to 20 cm, hydrophilic rounded tip, individual packaging</td></tr></tbody></table>' WHERE id = 523;
UPDATE product SET name_en = 'Auricular Speculum (Greatcare) (Multiple Sizes)', description_en = '<p><strong>Auricular Speculum (Greatcare) (Multiple Sizes)</strong> is a high-quality medical instrument designed for professional ear examinations. Made from high-quality 304 stainless steel, this speculum provides not only exceptional durability but also optimal biocompatibility, ensuring patient safety and comfort. Its ergonomic structure assists healthcare professionals in performing ear inspections easily and precisely.</p> <p>With ethylene oxide (EO) sterilization, the Auricular Speculum ensures perfect asepsis, essential in clinical settings where infection prevention is crucial. The product is available in several sizes (small, medium, large), allowing for individual adaptation to each patient, enhancing user experience, and minimizing trauma risks with an atraumatic rounded tip.</p> <p>This device is CE certified, reflecting its adherence to the stringent health and safety standards of the European Union. Intended exclusively for professional use in clinics or hospitals, it is individually packaged in sterile packaging, providing additional safety during storage and use. The Auricular Speculum (Greatcare) is an ideal choice for professionals seeking to optimize their clinical practices with reliable and sophisticated equipment.</p> <table class="table-fixed w-full border-separate border-spacing-2 border border-gray-300"> <thead> <tr class="bg-gray-100"> <th class="border border-gray-300 p-2">Material</th> <th class="border border-gray-300 p-2">Sterilization</th> <th class="border border-gray-300 p-2">Compliance</th> <th class="border border-gray-300 p-2">Clinical Use</th> <th class="border border-gray-300 p-2">Features</th> </tr> </thead> <tbody> <tr> <td class="border border-gray-300 p-2">304 Stainless Steel</td> <td class="border border-gray-300 p-2">Ethylene Oxide (EO)</td> <td class="border border-gray-300 p-2">CE Certified</td> <td class="border border-gray-300 p-2">Professional clinical or hospital use</td> <td class="border border-gray-300 p-2">Available in multiple sizes (small, medium, large), Rounded tip for optimal comfort, Individual sterile packaging</td> </tr> </tbody> </table>' WHERE id = 571;
UPDATE product SET name_en = 'Spinal Needle (Quincke Bevel) (Multiple Sizes)', description_en = '<p class="text-lg leading-relaxed font-light text-gray-700">The Spinal Needle (Quincke Bevel) is a premium medical device designed to offer exceptional performance and optimal safety during clinical and hospital interventions. Made of 304 stainless steel, this needle is renowned for its robustness and corrosion resistance, ensuring unquestionable biocompatibility. The Quincke-type design ensures atraumatic tissue penetration, minimizing trauma and enhancing patient comfort.</p><p class="text-lg leading-relaxed font-light text-gray-700">Intended for clinical use, this sterile single-use needle is perfect for performing lumbar punctures and other procedures requiring precise penetration. Each needle undergoes a rigorous ethylene oxide (EO) sterilization process, ensuring microbial safety and delivery in a sterile state. Its compliance with CE standards attests to its adherence to European quality standards, enhancing its reliability among healthcare practitioners worldwide.</p><p class="text-lg leading-relaxed font-light text-gray-700">Available in multiple sizes (20G to 27G), the Spinal Needle (Quincke Bevel) offers flexibility and adaptability for various clinical needs. The Quincke bevel is designed to maximize penetration efficiency while preserving tissue integrity. Its ergonomic design aids healthcare professionals in their clinical endeavors, ensuring precise and controlled actions. Designed for the demanding environments of medical centers and hospitals, it represents an indispensable tool for specialists in search of precision and safety.</p><table class="min-w-full bg-white border border-gray-200 mt-4"><thead class="bg-gray-50"><tr><th class="py-2 px-4 border-b border-gray-200 font-semibold text-gray-700 text-left">Specification</th><th class="py-2 px-4 border-b border-gray-200 font-semibold text-gray-700 text-left">Details</th></tr></thead><tbody><tr><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Material</td><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Stainless Steel 304</td></tr><tr><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Sterilization</td><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Ethylene Oxide (EO)</td></tr><tr><td class="py-2 px-4 border-b border-gray-200 text-gray-600">CE / ISO Compliance</td><td class="py-2 px-4 border-b border-gray-200 text-gray-600">CE Certification</td></tr><tr><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Clinical Use</td><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Clinical and hospital settings</td></tr><tr><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Features</td><td class="py-2 px-4 border-b border-gray-200 text-gray-600">Sterile, single-use, Tip type: Quincke Bevel</td></tr></tbody></table>' WHERE id = 9;
UPDATE product SET name_en = 'Coloplast Intermittent Catheter for Children Ch.8', description_en = '<div class="max-w-lg mx-auto">
    <p class="mb-4">The Coloplast Intermittent Pediatric Catheter Ch.8 represents a significant advancement in terms of ergonomics and safety for pediatric urological procedures. Specifically designed to meet the delicate needs of young patients, this catheter uses high-grade medical PVC to ensure not only biocompatibility but also optimal flexibility that minimizes the risk of irritation or trauma during use. The length of 30 cm and the Ch.8 size (equivalent to an outer diameter of 2.7 mm) are perfectly adjusted for infant anatomies.</p>
    <p class="mb-4">Each catheter is sterilized with ethylene oxide (EO), ensuring rigorous sterility recognized by CE standards. Designed for single use, it is individually packaged to maintain sterility and optimize the control of nosocomial infections. The ergonomic design includes an atraumatic rounded tip to facilitate smooth introduction and reduce the risk of complications during interventions.</p>
    <p class="mb-4">This medical device comes with full CE compliance, certifying that every aspect of its production, from material selection to final inspection, meets the strictest European standards of safety and efficacy. With its sophisticated design, this catheter is a reliable solution for healthcare professionals, ensuring both the safety of young patients and the effectiveness of treatment.</p>
    <table class="table-auto mx-auto w-full border-collapse">
        <thead class="bg-gray-300">
            <tr>
                <th class="py-2 px-4 border">Features</th>
                <th class="py-2 px-4 border">Description</th>
            </tr>
        </thead>
        <tbody>
            <tr>
                <td class="py-2 px-4 border">Material</td>
                <td class="py-2 px-4 border">High-grade medical PVC</td>
            </tr>
            <tr>
                <td class="py-2 px-4 border">Sterilization</td>
                <td class="py-2 px-4 border">Ethylene Oxide (EO)</td>
            </tr>
            <tr>
                <td class="py-2 px-4 border">CE / ISO Compliance</td>
                <td class="py-2 px-4 border">CE Certified</td>
            </tr>
            <tr>
                <td class="py-2 px-4 border">Clinical Use</td>
                <td class="py-2 px-4 border">Sterile single use</td>
            </tr>
            <tr>
                <td class="py-2 px-4 border">Features</td>
                <td class="py-2 px-4 border">Individually packaged, Atraumatic rounded tip</td>
            </tr>
        </tbody>
    </table>
</div>' WHERE id = 526;
UPDATE product SET name_en = 'Catheter Mount (Multi-Sizes)', description_en = '<p>The Catheter Mount (Multi-Sizes), SKU: RUS191014-000200, is designed to meet the most demanding expectations of healthcare professionals in terms of clinical performance and patient safety. Made from medical-grade silicone, it ensures optimal biocompatibility, thereby reducing the risk of immune reaction or irritation in patients. The silicone offers exceptional flexibility, ensuring atraumatic passage and secure insertion, minimizing discomfort and tissue trauma.</p><p>Ethylene oxide (EO) sterilization ensures total asepsis, making this product ready for use immediately upon opening. Each unit is carefully packed in an individual sterile package to maintain this condition until use, ensuring maximum protection against contamination. Available in various sizes from 14G to 22G, this catheter mount is suitable for a wide range of clinical applications, from standard infusions to precision sampling.</p><p>CE-certified, the Catheter Mount complies with the highest standards of the medical industry, attesting to its quality and clinical safety. Additionally, its carefully designed beveled tip allows for smooth and uniform penetration, reducing potential trauma during insertion. Its ergonomic design facilitates handling by nursing and medical staff, thus increasing operational efficiency. This product is intended for single professional use, ensuring safe and effective medical practices.</p><table style="width:100%; border-collapse:collapse; border:1px solid #ddd; font-family:Arial, sans-serif;"><tr><th style="border:1px solid #ddd; padding:8px;">Specification</th><th style="border:1px solid #ddd; padding:8px;">Detail</th></tr><tr><td style="border:1px solid #ddd; padding:8px;">Material</td><td style="border:1px solid #ddd; padding:8px;">Medical-grade silicone</td></tr><tr><td style="border:1px solid #ddd; padding:8px;">Sterilization</td><td style="border:1px solid #ddd; padding:8px;">Ethylene oxide (EO)</td></tr><tr><td style="border:1px solid #ddd; padding:8px;">Compliance</td><td style="border:1px solid #ddd; padding:8px;">CE</td></tr><tr><td style="border:1px solid #ddd; padding:8px;">Clinical Use</td><td style="border:1px solid #ddd; padding:8px;">Single-use, professional</td></tr><tr><td style="border:1px solid #ddd; padding:8px;">Features</td><td style="border:1px solid #ddd; padding:8px;">Beveled tip, individual sterile packaging</td></tr></table><p>This medical device is designed with high clinical quality materials. Key technical features include: <strong>Type</strong>: Corrugated, extendable. <strong>Dead Volume</strong>: 15 ml (minimizes CO2 re-inhalation). <strong>Connectivity</strong>: Standard connectors 22F/15M - 15F. <strong>Sterilization</strong>: Single-use, sterile packaging. <strong>Clinical Use</strong>: Connection between respiratory circuit and patient tube.</p>' WHERE id = 54;
UPDATE product SET name_en = 'Non-Sterile Examination Gloves (Multi-Sizes)', description_en = '<p class="text-lg leading-relaxed">The <strong>Non-Sterile Examination Gloves (Multi-Sizes)</strong>, SKU: NEO152100, provide a proven solution for clinical and hospital needs. Made from <em>nitrile</em>, a material renowned for its exceptional properties of <strong>biocompatibility</strong> and resistance, these gloves offer reliable protection against a wide range of contaminants. The non-sterile nature of these gloves makes them suitable for non-invasive procedures where sterile contact is not required.</p><p class="text-lg leading-relaxed">These gloves are designed to be <strong>ergonomic</strong>, ensuring optimal comfort during long periods of use. Available in several sizes - <em>Small, Medium, Large, and Extra-large</em> - they provide an atraumatic fit, minimizing the risk of fatigue or skin irritation. The nitrile composition confers high puncture resistance, offering an ideal combination of protection and flexibility.</p><p class="text-lg leading-relaxed">These gloves meet <strong>CE compliance</strong> standards, ensuring they adhere to current quality and safety standards. Packaged in boxes of 100, they are easy to store and ready for <strong>single-use</strong>. Their distinctive blue color allows for quick identification and reduces the risk of cross-contamination.</p><table class="min-w-full border-collapse"><thead><tr class="bg-gray-200"><th class="border-b px-4 py-2 text-left">Features</th><th class="border-b px-4 py-2 text-left">Details</th></tr></thead><tbody><tr><td class="border-b px-4 py-2">Material</td><td class="border-b px-4 py-2">Nitrile</td></tr><tr><td class="border-b px-4 py-2">Sterilization</td><td class="border-b px-4 py-2">Non-sterile</td></tr><tr><td class="border-b px-4 py-2">CE/ISO Compliance</td><td class="border-b px-4 py-2">CE Certification</td></tr><tr><td class="border-b px-4 py-2">Clinical Use</td><td class="border-b px-4 py-2">Single use in clinical or hospital setting</td></tr><tr><td class="border-b px-4 py-2">Features</td><td class="border-b px-4 py-2">Puncture resistance, Biocompatibility, Ergonomics</td></tr></tbody></table>' WHERE id = 562;
UPDATE product SET name_en = 'Non-Cuffed Endotracheal Tube (Multi-Sizes)', description_en = '<p>The Non-Cuffed Endotracheal Tube (Multi-Sizes) is designed to offer superior performance during tracheal intubation procedures. Made from high-quality medical silicone, this tube ensures exceptional biocompatibility, reducing the risks of adverse reactions in sensitive mucosal tissue. Its robust construction ensures easy handling while providing optimal flexibility to anatomically adapt to the patient.</p><p>Each tube is sterilized using ethylene oxide (EO) to ensure purity and clinical safety. EO sterilization is well recognized for preserving material integrity while effectively eliminating microbiological contamination. Intended for single use, the tube guarantees high hygiene standards and minimizes cross-infection risks.</p><p>Equipped with an atraumatic rounded tip, this tube reduces trauma during insertion, thereby enhancing patient comfort. With a length varying from 200 to 300 mm, it allows for a wide range of clinical applications, meeting the varied needs of healthcare professionals in intubation. CE compliance certifies that this device meets essential safety and performance requirements. Each is packaged individually and sterile, ensuring aseptic handling until point of use.</p><table class="min-w-full border border-gray-300"><thead><tr><th class="border-b-2 border-gray-300 px-4 py-2 text-left">Specification</th><th class="border-b-2 border-gray-300 px-4 py-2 text-left">Details</th></tr></thead><tbody><tr><td class="border-t border-gray-300 px-4 py-2">Material</td><td class="border-t border-gray-300 px-4 py-2">High-quality medical silicone</td></tr><tr><td class="border-t border-gray-300 px-4 py-2">Sterilization</td><td class="border-t border-gray-300 px-4 py-2">Ethylene oxide (EO)</td></tr><tr><td class="border-t border-gray-300 px-4 py-2">Compliance</td><td class="border-t border-gray-300 px-4 py-2">CE</td></tr><tr><td class="border-t border-gray-300 px-4 py-2">Clinical Use</td><td class="border-t border-gray-300 px-4 py-2">Single use for tracheal intubation</td></tr><tr><td class="border-t border-gray-300 px-4 py-2">Features</td><td class="border-t border-gray-300 px-4 py-2">Atraumatic rounded tip, length 200-300 mm, individual sterile packaging</td></tr></tbody></table><p>This medical device is designed with high clinical quality materials. Key technical features include: <strong>Material</strong>: Transparent medical thermosensitive PVC. <strong>Cuff</strong>: None (Ideal for strict pediatric use). <strong>Bevel</strong>: Atraumatic Murphy type. <strong>Marking</strong>: Clear insertion graduations (cm). <strong>Clinical Use</strong>: Short-term neonatal/pediatric intubation.</p>' WHERE id = 23;
UPDATE product SET name_en = 'Tracheofix Kit Without Cuff (Multi-Sizes)', description_en = '<p>The Tracheofix Kit Without Cuff (Multi-Sizes) is an advanced care solution designed to provide healthcare professionals with optimal performance in clinical or hospital settings. This device is distinguished by the use of high-quality polyurethane material, ensuring exceptional biocompatibility and long-term resistance. Thanks to its multi-size design, it easily adapts to a wide variety of patients, ensuring increased comfort and safety during use.</p><p>Ethylene oxide (EO) sterilization ensures the product''s microbiological purity and safety, effectively preventing nosocomial infections. Fully compliant with CE standards and recognized for its reliability, the Tracheofix Kit Without Cuff simplifies clinical processes through its packaging in individual sterile packages, thus minimizing the risk of cross-contamination.</p><p>The ergonomic features of the device, particularly its atraumatic blunt tip, allow for gentle and trauma-free introduction for the patient, reducing the risks of complications. This technical innovation reflects our engineers'' dedication to developing medical instruments that meet the rigorous demands of modern practitioners.</p><table class="w-full border-collapse"><thead><tr class="bg-gray-100"><th class="border p-2">Specification</th><th class="border p-2">Details</th></tr></thead><tbody><tr><td class="border p-2">Material</td><td class="border p-2">Polyurethane</td></tr><tr><td class="border p-2">Sterilization</td><td class="border p-2">Ethylene oxide (EO)</td></tr><tr><td class="border p-2">CE/ISO Compliance</td><td class="border p-2">CE approved</td></tr><tr><td class="border p-2">Clinical Use</td><td class="border p-2">Clinical or hospital use</td></tr><tr><td class="border p-2">Features</td><td class="border p-2">Atraumatic blunt tip, Multi-sizes</td></tr></tbody></table>' WHERE id = 500;
UPDATE product SET name_en = 'Laryngoscope With Blades – Cullinan (Multi-Sizes)', description_en = '<p>The Laryngoscope With Blades - Cullinan (Multi-Sizes), reference HUGVL4R432, is a top-class medical device designed for healthcare professionals demanding reliability and performance. Made from 304 stainless steel, this laryngoscope guarantees optimal biocompatibility and exceptional durability, even in the most demanding clinical environments. 304 stainless steel provides resistance to both wear and corrosion, offering a long-lasting solution for airway visualization.</p><p>This device is sterilized using ethylene oxide (EO), a method recognized for its effectiveness in eliminating all microorganisms, thus ensuring maximum safety and hygiene. Certified CE, this laryngoscope complies with the strictest quality and safety standards, ensuring practitioners a confident use in their daily procedures.</p><p>Available in several interchangeable sizes (4/3/2, 00/0/1, 5/4/1), this precision instrument offers ergonomic and adaptable features that maximize user comfort. Its atraumatic design reduces the risk of soft tissue injury, while the individual box packaging facilitates transport and storage. Versatile and efficient, the Cullinan laryngoscope is an essential tool in the arsenal of current instruments for anesthesia and emergency.</p><table class="min-w-full bg-white"><thead class="border-b"><tr class="bg-gray-200"><th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Feature</th><th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Specification</th></tr></thead><tbody class="bg-white divide-y divide-gray-200"><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Material</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">304 Stainless Steel</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Sterilization</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Ethylene oxide (EO)</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">CE/ISO Compliance</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">CE</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Clinical Use</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Medical professional</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Features</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Interchangeable blade, individual box, ergonomic design</td></tr></tbody></table>' WHERE id = 60;
UPDATE product SET name_en = 'General Practitioner Consultation Kit', description_en = '<p>The General Practitioner Consultation Kit, SKU: KIT-GEN-001, is designed to meet essential needs of healthcare professionals during medical consultations. This kit reflects a commitment to quality and safety and includes components carefully selected for their durability, biocompatibility, and compliance with the highest clinical standards.</p><p>The beechwood tongue depressors, chosen for their sturdiness and allergen neutrality, ensure a safe and atraumatic use during oral examinations. The powder-free nitrile gloves are medium-sized, providing excellent ergonomics and optimal comfort for the user, while offering chemical resistance and protection against infectious agents. These gloves meet the expectations for flexibility and tactile sensitivity required in medical settings.</p><p>The Type IIR masks, compliant with the EN 14683:2019 standard, provide reliable protection against particles and pathogens during procedures. Their design offers high breathability without compromising safety. To complete this kit, the 500 ml hand sanitizer gel, containing 70% ethanol, ensures effective and quick hand disinfection, in line with hospital hygiene recommendations.</p><table class="min-w-full divide-y divide-gray-200"><thead class="bg-gray-50"><tr><th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Specification</th><th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th></tr></thead><tbody class="bg-white divide-y divide-gray-200"><tr><td class="px-6 py-4 whitespace-nowrap">Tongue Depressors Material</td><td class="px-6 py-4 whitespace-nowrap">Beechwood</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Gloves Material</td><td class="px-6 py-4 whitespace-nowrap">Powder-free Nitrile</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Gloves Size</td><td class="px-6 py-4 whitespace-nowrap">Medium</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Mask Type</td><td class="px-6 py-4 whitespace-nowrap">Type IIR</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Mask Standard</td><td class="px-6 py-4 whitespace-nowrap">EN 14683:2019</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Hand Sanitizer Volume</td><td class="px-6 py-4 whitespace-nowrap">500 ml</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Alcohol Concentration in Gel</td><td class="px-6 py-4 whitespace-nowrap">70% Ethanol</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Sterilization</td><td class="px-6 py-4 whitespace-nowrap">Not Applicable</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">CE Compliance</td><td class="px-6 py-4 whitespace-nowrap">Yes, compliant with current clinical standards</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Clinical Use</td><td class="px-6 py-4 whitespace-nowrap">General Consultation</td></tr><tr><td class="px-6 py-4 whitespace-nowrap">Features</td><td class="px-6 py-4 whitespace-nowrap">Biocompatibility, high durability, ergonomics, optimal protection</td></tr></tbody></table>' WHERE id = 10002;
UPDATE product SET name_en = 'Guedel Airway (Multi-Sizes)', description_en = '<p>The Guedel Airway (Multi-Sizes), referenced under SKU RUS124900-000001, represents an advancement in the field of clinical respiratory support. Designed to provide optimal support during respiratory care administration, this medical device is essential in modern clinics and hospitals. Made from high-quality medical plastic, the airway guarantees maximum biocompatibility with human tissues, thus ensuring safe use.</p><p>Thanks to its ergonomic design, the airway integrates seamlessly into medical procedures, allowing for safe and effective intubation due to its open tip. The variety of sizes, ranging from 00 to 6, ensures a perfect adaptation to each morphology, thereby reducing complications and enhancing patient comfort. The ethylene oxide (EO) sterilization process guarantees a ready-to-use product while ensuring long-term sterility.</p><p>CE certified for medical devices, the Guedel Airway complies with the most stringent safety and performance standards. Each airway is individually packaged to preserve sterility until use. This individual packaging also facilitates storage and handling while minimizing the risks of cross-contamination.</p><table class="min-w-full border-collapse bg-white"><thead><tr><th class="px-6 py-4 border-b font-medium text-gray-500">Technical Specifications</th><th class="px-6 py-4 border-b font-medium text-gray-500"></th></tr></thead><tbody><tr><td class="border-t px-6 py-4 text-gray-700">Material</td><td class="border-t px-6 py-4 text-gray-700">High-quality medical plastic</td></tr><tr class="bg-gray-50"><td class="border-t px-6 py-4 text-gray-700">Sterilization</td><td class="border-t px-6 py-4 text-gray-700">Ethylene Oxide (EO)</td></tr><tr><td class="border-t px-6 py-4 text-gray-700">CE / ISO Compliance</td><td class="border-t px-6 py-4 text-gray-700">CE certified for medical devices</td></tr><tr class="bg-gray-50"><td class="border-t px-6 py-4 text-gray-700">Clinical Use</td><td class="border-t px-6 py-4 text-gray-700">Respiratory support in clinic or hospital</td></tr><tr><td class="border-t px-6 py-4 text-gray-700">Features</td><td class="border-t px-6 py-4 text-gray-700">Size from 00 to 6 (multi-sizes available), Open tip for secure intubation, Individually packaged</td></tr></tbody></table><p>This medical device is crafted with clinical-grade materials. Key technical features: <strong>Material</strong>: Semi-rigid polymer (PE) and rigid insert (PP). <strong>Design</strong>: Anatomical anti-bite shape with ISO color code. <strong>Sterilization</strong>: Ethylene Oxide (EO). <strong>Clinical Use</strong>: Maintenance of upper airway patency.</p>' WHERE id = 45;
UPDATE product SET name_en = '1 ml Insulin Syringe with 29G Fixed Needle', description_en = '<p>The 1 ml insulin syringe with a 29G fixed needle, referenced under SKU: NEO176501/29, is a high-precision medical device designed to ensure safe and effective insulin administration. Its precise one milliliter capacity is ideal for applications requiring exact dosing, thereby optimizing the management of insulin therapy. The 29G needle, made from surgical-grade stainless steel, features an atraumatic tip to minimize patient discomfort while ensuring smooth and precise penetration.</p><p>In terms of biocompatibility, this product is sterilized by ethylene oxide (EO), offering a high level of sterility, compliant with international safety standards. The syringe barrel is made of transparent polypropylene to provide good visibility of the content, facilitating correct and precise insulin administration. The device''s ergonomics are optimized for secure and comfortable handling, allowing healthcare professionals to perform injections with ease and confidence.</p><p>This device is CE certified, attesting to its compliance with safety and performance regulatory requirements. Intended for single use, it ensures adherence to hygiene protocols and prevents the risk of cross-contamination. Each syringe is individually packaged in a sterile manner, guaranteeing maximum integrity until the moment of use. This insulin syringe is specifically intended for clinical use, meeting the needs of healthcare professionals involved in the daily management of diabetic patients.</p><table class=''min-w-full divide-y divide-gray-200''><thead class=''bg-gray-50''><tr><th class=''px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider''>Material</th><th class=''px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider''>Sterilization</th><th class=''px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider''>Compliance</th><th class=''px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider''>Clinical Use</th><th class=''px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider''>Features</th></tr></thead><tbody class=''bg-white divide-y divide-gray-200''><tr><td class=''px-6 py-4 whitespace-nowrap''>Polypropylene barrel</td><td class=''px-6 py-4 whitespace-nowrap''>Ethylene Oxide (EO)</td><td class=''px-6 py-4 whitespace-nowrap''>CE Certified</td><td class=''px-6 py-4 whitespace-nowrap''>Single use</td><td class=''px-6 py-4 whitespace-nowrap''>29G fixed needle, atraumatic tip, sterile individual packaging</td></tr></tbody></table>' WHERE id = 559;
UPDATE product SET name_en = 'Coloplast One-Piece Pediatric Urostomy Pouch Alterna Transp', description_en = '<p>The Coloplast One-Piece Pediatric Urostomy Pouch Alterna Transp is a high-quality urinary pouch solution dedicated to pediatric use. Made from medical-grade silicone, this pouch offers optimal biocompatibility, ensuring atraumatic and safe contact with children''s delicate skin. Its transparency allows for easy and continuous monitoring, ensuring effective clinical follow-up.</p><p>Featuring an ergonomics designed for children, this pouch is lightweight and discreetly worn under clothing. Although non-sterile, it complies with rigorous CE conformity standards, ensuring superior safety and uncompromising reliability. With a capacity of 120 ml, it is ideal for meeting the specific needs of the pediatric population.</p><p>A key feature of this product is its practicality. The packaging in boxes of 20 units aims to facilitate inventory management and ensure a clean solution is always on hand. These pouches are ideal for daily use and are recommended by healthcare professionals for their proven performance and design respecting children''s physiology.</p><table class="min-w-full divide-y divide-gray-200"><thead class="bg-gray-50"><tr><th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Feature</th><th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Detail</th></tr></thead><tbody class="bg-white divide-y divide-gray-200"><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Material</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Medical silicone</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Sterilization</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Non-sterile</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">CE / ISO Compliance</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">CE</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Clinical Use</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Pediatric use</td></tr><tr><td class="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">Characteristics</td><td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500">120 ml capacity, Box of 20 units, Transparent for clinical monitoring, Ergonomic design for children</td></tr></tbody></table>' WHERE id = 509;
UPDATE product SET name_en = 'Coloplast One-Piece Urostomy Pouch Alterna Free White', description_en = '<div style="font-family: Arial, sans-serif; color: #333; max-width: 800px; margin: 0 auto;"><p style="font-size: 1.2em; line-height: 1.6;">The Coloplast One-Piece Urostomy Pouch Alterna Free White, SKU: COL175210, is a high-quality medical device designed for professional clinical and hospital use. Engineered to optimize user compatibility and tolerance, this product is made from premium medical-grade silicone, renowned for its exceptional biocompatibility and chemical resistance. The ergonomic and attractive design ensures optimal comfort during use, minimizing the risk of friction or irritation.</p><p style="font-size: 1.2em; line-height: 1.6;">The ethylene oxide (EO) sterilization technique guarantees maximum purity and safety, essential in rigorous clinical environments. Featuring a 500 mL capacity, this pouch offers sufficient volume to meet the varied needs of patients, facilitating effective and hygienic management of bodily fluids. The EO sterilization process, recognized for its deep penetration and effectiveness, ensures each unit is safe and reliable for use.</p><p style="font-size: 1.2em; line-height: 1.6;">CE certified to rigorous standards, the pouch is individually blister-packaged sterile, maintaining optimal sterility until opening at the time of use. This level of certification provides further assurance of the product''s quality, granting peace of mind to healthcare professionals regarding the integrity and safety of the device throughout its life cycle.</p><p style="font-size: 1.2em; line-height: 1.6;">In conclusion, the Coloplast One-Piece Urostomy Pouch Alterna Free White combines reliability, safety, and user comfort to precisely meet the high demands of the medical field. Its innovative design contributes to improving professional practices and the quality of care provided.</p><table style="width: 100%; border-collapse: collapse; margin-top: 20px;"><thead style="background-color: #f5f5f5;"><tr><th style="border: 1px solid #ddd; padding: 8px; text-align: left;">Specification</th><th style="border: 1px solid #ddd; padding: 8px; text-align: left;">Details</th></tr></thead><tbody><tr><td style="border: 1px solid #ddd; padding: 8px;">Material</td><td style="border: 1px solid #ddd; padding: 8px;">Medical silicone</td></tr><tr><td style="border: 1px solid #ddd; padding: 8px;">Sterilization</td><td style="border: 1px solid #ddd; padding: 8px;">Ethylene Oxide (EO)</td></tr><tr><td style="border: 1px solid #ddd; padding: 8px;">Compliance</td><td style="border: 1px solid #ddd; padding: 8px;">CE Certification</td></tr><tr><td style="border: 1px solid #ddd; padding: 8px;">Clinical Use</td><td style="border: 1px solid #ddd; padding: 8px;">Professional clinical and hospital use</td></tr><tr><td style="border: 1px solid #ddd; padding: 8px;">Characteristics</td><td style="border: 1px solid #ddd; padding: 8px;">Dimensions: 200 mm x 130 mm, Capacity: 500 mL, Packaging: Individual sterile blister</td></tr></tbody></table></div>' WHERE id = 510;
UPDATE product SET name_en = '3-Piece Luer Slip Syringe (Multiple Sizes)', description_en = '<p>The 3-Piece Luer Slip Syringe (Multiple Sizes) SKU: NEO176550SLIP is designed to meet the highest medical industry standards. Made of medical-grade polypropylene, it offers superior biocompatibility, ensuring safety and reliability during clinical use. Its three-piece design provides precise medication control while minimizing risks of leakage or spillage. The syringe''s clear barrel allows for optimal visual content inspection, aiding healthcare practitioners.</p>

<p>Sterilized by ethylene oxide (EO), each syringe is individually packaged to ensure maximum sterility until use. The Luer Slip tip type allows for quick and secure connections with various medical accessories, facilitating efficient medication delivery. An atraumatic design principle enhances patient comfort.</p>

<p>This product is CE certified, denoting compliance with the most stringent quality and safety standards. The syringes are intended for single use, reducing cross-contamination risks and adhering to best clinical practices. They are available in multiple capacities—2 ml, 5 ml, 10 ml, and 20 ml—providing a flexible solution for diverse medical needs.</p>

